import type { Meta, StoryObj } from '@storybook/react-vite';
import { Popover } from './Popover';
import { Button } from '../Button';
import { Text } from '../Text';
import { Space } from '../Space';

const triggerButton = <Button type="primary">Open popover</Button>;

const placements = [
  'top',
  'top-start',
  'top-end',
  'bottom',
  'bottom-start',
  'bottom-end',
  'left',
  'right',
] as const;

const meta = {
  title: 'Components/Popover',
  component: Popover,
  tags: ['autodocs'],
  argTypes: {
    content: { control: 'text' },
    title: { control: 'text' },
    trigger: { control: 'inline-radio', options: ['hover', 'click', 'focus'] },
    placement: { control: 'select', options: placements },
    width: { control: 'text' },
    showArrow: { control: 'boolean' },
    offset: { control: 'number' },
    disabled: { control: 'boolean' },
    open: { control: false },
    defaultOpen: { control: false },
    onOpenChange: { control: false },
    children: { control: false },
  },
  args: {
    title: 'Project details',
    content: 'Shipped on June 18, 2026. Owned by the platform team.',
    trigger: 'click',
    placement: 'bottom',
    width: 240,
    // Satisfies the required `children` prop; stories override it via `render`.
    children: triggerButton,
  },
} satisfies Meta<typeof Popover>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Playground: Story = {
  render: (args) => (
    <Popover {...args}>
      <Button type="primary">Open popover</Button>
    </Popover>
  ),
};

export const WithTitle: Story = {
  name: 'With a title',
  render: () => (
    <Popover
      title="Keyboard shortcuts"
      content="Press Cmd+K to open the command palette."
      width={260}
    >
      <Button>Show shortcuts</Button>
    </Popover>
  ),
};

export const RichContent: Story = {
  name: 'Rich content',
  render: () => (
    <Popover
      title="Invite teammates"
      width={280}
      content={
        <Space direction="vertical">
          <Text>Share a link or send an invitation by email.</Text>
          <Space>
            <Button size="small">Copy link</Button>
            <Button size="small" type="primary">
              Send invite
            </Button>
          </Space>
        </Space>
      }
    >
      <Button type="primary">Invite</Button>
    </Popover>
  ),
};

export const HoverTrigger: Story = {
  name: 'Hover trigger',
  render: () => (
    <Popover trigger="hover" content="Opens while the trigger is hovered." placement="right">
      <Button>Hover me</Button>
    </Popover>
  ),
};

import {
  cloneElement,
  forwardRef,
  isValidElement,
  type ReactElement,
  type ReactNode,
} from 'react';
import { useNamespace } from '../../utils';
import { type Placement, Popper } from '../Overlay';

export type PopoverTrigger = 'hover' | 'click' | 'focus';

export interface PopoverProps {
  /** Popover body content. */
  content: ReactNode;
  /** Optional bold heading shown above the content. */
  title?: ReactNode;
  /** How the popover opens. */
  trigger?: PopoverTrigger;
  /** Placement of the popover relative to the trigger. */
  placement?: Placement;
  /** Fixed width of the popover surface. */
  width?: number | string;
  /** Show the arrow pointing at the trigger. */
  showArrow?: boolean;
  /** Gap between the trigger and the popover, in px. */
  offset?: number;
  /** Disable the popover; the trigger renders without one. */
  disabled?: boolean;
  /** Controlled open state. */
  open?: boolean;
  /** Initial open state when uncontrolled. */
  defaultOpen?: boolean;
  /** Fired when the open state changes. */
  onOpenChange?: (open: boolean) => void;
  /** Trigger element. */
  children: ReactElement;
}

export const Popover = forwardRef<HTMLDivElement, PopoverProps>(function Popover(props, ref) {
  const {
    content,
    title,
    trigger = 'click',
    placement = 'bottom',
    width,
    showArrow = true,
    offset = 8,
    disabled = false,
    open,
    defaultOpen,
    onOpenChange,
    children,
  } = props;

  const ns = useNamespace('popover');

  if (!isValidElement(children)) {
    return <>{children}</>;
  }

  const reference = ref ? cloneElement(children, { ref } as Record<string, unknown>) : children;

  return (
    <Popper
      reference={reference}
      trigger={trigger}
      placement={placement}
      offset={offset}
      role="dialog"
      showArrow={showArrow}
      disabled={disabled}
      popperClass={ns.b()}
      popperStyle={width != null ? { width } : undefined}
      open={open}
      defaultOpen={defaultOpen}
      onOpenChange={onOpenChange}
    >
      {title != null && title !== '' && <div className={ns.e('title')}>{title}</div>}
      <div className={ns.e('content')}>{content}</div>
    </Popper>
  );
});

.ec-popover {
  --ec-popover-padding: 12px;
  --ec-popover-font-size: var(--ec-font-size-base);
  --ec-popover-title-font-size: var(--ec-font-size-base);

  box-sizing: border-box;
  min-width: 150px;
  max-width: 320px;
  padding: var(--ec-popover-padding);
  font-size: var(--ec-popover-font-size);
  line-height: 1.5;
  color: var(--ec-text-color-regular);
}

.ec-popover__title {
  box-sizing: border-box;
  margin: 0 0 8px;
  font-size: var(--ec-popover-title-font-size);
  font-weight: var(--ec-font-weight-primary);
  color: var(--ec-text-color-primary);
  line-height: 1.4;
}

.ec-popover__content {
  box-sizing: border-box;
  color: var(--ec-text-color-regular);
}
